mapper.select:
select u.id, u.username, u.real_name as name, u.phone, u.email, u.status from sys_user u where not exists ( select 1 from sys_user_role ur where ur.user_id = u.id and ur.role_id = #{query.roleId} )
and ( u.username like concat('%', #{query.keyword}, '%') or u.real_name like concat('%', #{query.keyword}, '%') or u.phone like concat('%', #{query.keyword}, '%') )
and
(
u.id = #{query.dataScopeUserId}
or
u.department_id in
#{deptId}
)
1 = 0
order by u.id desc limit #{query.pageSize} offset #{query.offset}

